import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void classicMixedValues() {
        // [1,12,-5,-6,50,3] k=4: window [12,-5,-6,50] sums to 51, avg = 12.75
        assertEquals(12.75, new Solution().maxAverage(
                new int[]{1, 12, -5, -6, 50, 3}, 4), 1e-9);
    }

    @Test
    void singleElement() {
        // k=1, single element array
        assertEquals(5.0, new Solution().maxAverage(new int[]{5}, 1), 1e-9);
    }

    @Test
    void wholeArrayOneWindow() {
        // k equals array length — only one window, average of all elements
        assertEquals(2.5, new Solution().maxAverage(new int[]{1, 2, 3, 4}, 4), 1e-9);
    }

    @Test
    void allNegatives() {
        // [-1,-2,-3] k=2: windows [-1,-2]=-3 and [-2,-3]=-5; max avg = -3/2 = -1.5
        assertEquals(-1.5, new Solution().maxAverage(new int[]{-1, -2, -3}, 2), 1e-9);
    }

    @Test
    void kEqualsOne() {
        // k=1: best window is the single max element
        assertEquals(7.0, new Solution().maxAverage(new int[]{3, 7, 2, 5}, 1), 1e-9);
    }

    @Test
    void uniformValues() {
        // All same value — every window has the same average
        assertEquals(4.0, new Solution().maxAverage(new int[]{4, 4, 4, 4, 4}, 3), 1e-9);
    }

    @Test
    void fractionalAverage() {
        // [1,2] k=2: avg = 1.5; tests non-integer double result
        assertEquals(1.5, new Solution().maxAverage(new int[]{1, 2}, 2), 1e-9);
    }
}
